const COOKIE_NAME = 'remember_me';
const COOKIE_EXPIRY_DAYS = 30;

function setRememberMe(username, passwordHash) {
    const expiryDate = new Date();
    expiryDate.setDate(expiryDate.getDate() + COOKIE_EXPIRY_DAYS);
    
    const cookieValue = btoa(JSON.stringify({
        username: username,
        passwordHash: passwordHash,
        timestamp: Date.now()
    }));
    
    document.cookie = `${COOKIE_NAME}=${cookieValue};expires=${expiryDate.toUTCString()};path=/;secure;samesite=strict`;
}

function getRememberMe() {
    const name = COOKIE_NAME + "=";
    const decodedCookie = decodeURIComponent(document.cookie);
    const ca = decodedCookie.split(';');
    
    for(let i = 0; i < ca.length; i++) {
        let c = ca[i];
        while (c.charAt(0) === ' ') {
            c = c.substring(1);
        }
        if (c.indexOf(name) === 0) {
            const cookieValue = c.substring(name.length, c.length);
            try {
                return JSON.parse(atob(cookieValue));
            } catch (e) {
                return null;
            }
        }
    }
    return null;
}

function clearRememberMe() {
    document.cookie = `${COOKIE_NAME}=;expires=Thu, 01 Jan 1970 00:00:00 GMT;path=/`;
}

function autoLogin() {
    const rememberData = getRememberMe();
    
    if (rememberData) {
        const now = Date.now();
        const age = now - rememberData.timestamp;
        
        if (age < (COOKIE_EXPIRY_DAYS * 24 * 60 * 60 * 1000)) {
            return {
                username: rememberData.username,
                passwordHash: rememberData.passwordHash
            };
        } else {
            clearRememberMe();
        }
    }
    return null;
}

